import { motion, useReducedMotion, type Variants } from 'framer-motion'

export default function BackgroundOrbs() {
  const shouldReduceMotion = useReducedMotion()

  // Define very slow, gentle drifting animations for the ambient orbs
  const orb1Variants: Variants = {
    animate: {
      x: [0, 40, -20, 0],
      y: [0, -30, 20, 0],
      scale: [1, 1.05, 0.95, 1],
      transition: {
        duration: 32,
        repeat: Infinity,
        repeatType: 'reverse' as const,
        ease: 'easeInOut',
      },
    },
  }

  const orb2Variants: Variants = {
    animate: {
      x: [0, -30, 40, 0],
      y: [0, 20, -40, 0],
      scale: [1, 0.95, 1.05, 1],
      transition: {
        duration: 28,
        repeat: Infinity,
        repeatType: 'reverse' as const,
        ease: 'easeInOut',
      },
    },
  }

  const orb3Variants: Variants = {
    animate: {
      x: [0, 25, -35, 0],
      y: [0, 35, -20, 0],
      scale: [1, 1.08, 0.92, 1],
      transition: {
        duration: 35,
        repeat: Infinity,
        repeatType: 'reverse' as const,
        ease: 'easeInOut',
      },
    },
  }

  const orb4Variants: Variants = {
    animate: {
      x: [0, -25, 20, 0],
      y: [0, -20, 30, 0],
      scale: [1, 0.92, 1.08, 1],
      transition: {
        duration: 30,
        repeat: Infinity,
        repeatType: 'reverse' as const,
        ease: 'easeInOut',
      },
    },
  }

  return (
    <div
      className="fixed inset-0 -z-10 overflow-hidden pointer-events-none select-none"
      aria-hidden="true"
    >
      {/* Orb 1: Soft Sky Blue - Top Left */}
      <motion.div
        variants={orb1Variants}
        animate={shouldReduceMotion ? undefined : 'animate'}
        className="absolute -left-10 -top-10 w-72 h-72 md:w-[450px] md:h-[450px] rounded-full bg-sky-300/15 blur-[60px] md:blur-[100px] transform-gpu"
        /* To adjust colors, change bg-sky-300/15 to another color/opacity */
        /* To adjust position, edit absolute positioning classes like -left-10 -top-10 */
      />

      {/* Orb 2: Soft Warm Amber - Top Right */}
      <motion.div
        variants={orb2Variants}
        animate={shouldReduceMotion ? undefined : 'animate'}
        className="absolute -right-20 top-20 w-80 h-80 md:w-[500px] md:h-[500px] rounded-full bg-brand-amber/12 blur-[80px] md:blur-[120px] transform-gpu"
        /* Custom brand warm amber color with very soft 12% opacity */
      />

      {/* Orb 3: Soft Sky Blue - Middle Right */}
      <motion.div
        variants={orb3Variants}
        animate={shouldReduceMotion ? undefined : 'animate'}
        className="absolute right-10 top-1/2 -translate-y-1/2 w-64 h-64 md:w-[400px] md:h-[400px] rounded-full bg-sky-200/12 blur-[70px] md:blur-[90px] transform-gpu"
      />

      {/* Orb 4: Soft Warm Amber - Bottom Left */}
      <motion.div
        variants={orb4Variants}
        animate={shouldReduceMotion ? undefined : 'animate'}
        className="absolute left-10 bottom-10 w-72 h-72 md:w-[450px] md:h-[450px] rounded-full bg-brand-amber/10 blur-[80px] md:blur-[110px] transform-gpu"
      />
    </div>
  )
}

'use client'

import Link from 'next/link'
