                            className={cn(
                              'px-4 py-2 text-[11px] font-body font-medium transition-colors text-left block text-brand-grey hover:text-brand-blue hover:bg-brand-sand/40',
                              isSubActive && 'bg-brand-sand text-brand-blue font-semibold'
