                            {sub.label}
                          </Link>
                        )
                      })}
                    </div>
                  </div>
                </li>
              )
            }

            return (
              <li key={link.href}>
                <Link
                  href={link.href}
                  className={cn(
                    'px-4 py-1.5 rounded-pill text-xs font-body font-medium transition-all duration-200 block text-brand-grey hover:text-brand-blue hover:bg-brand-sand/40 relative',
                    isActive && 'bg-brand-blue text-white hover:text-white hover:bg-brand-blue/90 shadow-elev-1'
                  )}
                >
                  {link.label}
                </Link>
              </li>
            )
          })}
        </ul>

        {/* Actions: Volunteer (Ghost) + Donate (Filled) */}
        <div className="flex items-center gap-3 flex-shrink-0">
          <Link
            href="/contact#volunteer"
            className="btn-ghost text-xs py-2 px-4 border border-brand-blue text-brand-blue hover:bg-brand-blue hover:text-white transition-all duration-200"
