import { type ClassValue, clsx } from 'clsx'
import { twMerge } from 'tailwind-merge'

// Utility function to merge Tailwind classes dynamically
export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs))
}

export function formatDate(dateString: string): string {
  return new Date(dateString).toLocaleDateString('en-IN', {
    day: 'numeric',
    month: 'long',
    year: 'numeric',
  })
}

export function slugify(str: string): string {
  return str
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/(^-|-$)/g, '')
}

@import url('https://fonts.googleapis.com/css2?family=Playfair+Display:ital,wght@0,400;0,500;0,600;0,700;1,400;1,600&family=Inter:wght@300;400;500;600;700&display=swap');

@import "tailwindcss";

/* ─── Keyframes (must be outside @theme) ────────────────── */
@keyframes fadeUp {
  from {
    opacity: 0;
    transform: translateY(24px);
  }

  to {
    opacity: 1;
    transform: translateY(0);
  }
}

@keyframes fadeInUp {
  0% {
    opacity: 0;
    transform: translateY(32px) scale(0.98);
  }
  100% {
    opacity: 1;
    transform: translateY(0) scale(1);
  }
}

@keyframes shimmer {
  0% { background-position: -200% center; }
  100% { background-position: 200% center; }
}

@keyframes pulseSoft {
  0%, 100% { opacity: 0.6; }
  50% { opacity: 1; }
}

@keyframes pulseDot {

  0%,
  100% {
    transform: scale(1);
    opacity: 1;
  }

  50% {
    transform: scale(1.4);
    opacity: 0.6;
  }
}

/* ─── Tailwind v4 Theme ──────────────────────────────────── */
@theme {
  /* Brand Colors */
  --color-brand-blue: #1A3A5C;
  --color-brand-blue-light: #4A7FA5;
  --color-brand-amber: #F0A92A;
  --color-brand-amber-dark: #D48B0E;
  --color-brand-cream: #FBF7F0;
  --color-brand-sand: #F0EAD8;
  --color-brand-charcoal: #1C1C1E;
  --color-brand-grey: #6E6A66;
  --color-brand-white: #FFFFFF;

  /* Font Families */
  --font-family-heading: 'Playfair Display', Georgia, serif;
  --font-family-body: 'Inter', system-ui, sans-serif;

  /* Border Radius */
  --radius-pill: 999px;

  /* Shadows */
  --shadow-card: 0 2px 16px 0 rgba(26, 58, 92, 0.08);
  --shadow-card-hover: 0 8px 32px 0 rgba(26, 58, 92, 0.16);
  --shadow-nav: 0 4px 24px 0 rgba(26, 58, 92, 0.10);

  /* Animations */
  --animate-fade-up: fadeUp 0.6s ease-out both;
  --animate-fade-in-up: fadeInUp 0.6s cubic-bezier(0.23, 1, 0.32, 1) both;
  --animate-shimmer: shimmer 2.5s infinite;
  --animate-pulse-soft: pulseSoft 3s ease-in-out infinite;
  --animate-pulse-dot: pulseDot 2s ease-in-out infinite;
}

/* ─── Root Variables ─────────────────────────────────────── */
:root {
  --section-y: clamp(60px, 8vw, 100px);
  --depth-flat: none;
  --depth-soft: 0 10px 30px rgba(0,0,0,0.06);
  --depth-medium: 0 20px 60px rgba(0,0,0,0.08);
}

/* ─── Base Resets ────────────────────────────────────────── */
*,
*::before,
*::after {
  box-sizing: border-box;
}

html {
  scroll-behavior: smooth;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
  overflow-x: hidden;
  max-width: 100%;
}

body {
  color: #1C1C1E;
  font-family: 'Inter', system-ui, sans-serif;
  line-height: 1.65;
  font-size: 16px;
  overflow-x: hidden;
  max-width: 100%;

  /* Layered luxury background */
  background-color: #FBF7F0;
  background-image:
    /* Warm amber radial — top-left anchor */
    radial-gradient(ellipse 80% 60% at 5% 0%, rgba(240, 169, 42, 0.05) 0%, transparent 65%),
    /* Cool blue radial — bottom-right anchor */
    radial-gradient(ellipse 70% 50% at 95% 100%, rgba(74, 127, 165, 0.05) 0%, transparent 60%);
}

body::before {
  content: "";
  position: fixed;
  inset: 0;
  pointer-events: none;
  background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 200 200' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noiseFilter'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.8' numOctaves='3' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noiseFilter)'/%3E%3C/svg%3E");
  opacity: 0.012;
  mix-blend-mode: overlay;
  z-index: 9999;
}

@media (prefers-contrast: more) {
  body::before {
    display: none;
  }
}

@media (prefers-reduced-motion: reduce) {
  body::before {
    display: none;
  }
}

@media (min-width: 1024px) {
  body {
    font-size: 18px;
  }
}

h1,
h2,
h3,
h4,
h5,
h6 {
  font-family: 'Playfair Display', Georgia, serif;
  line-height: 1.2;
  color: #1C1C1E;
}

::selection {
  background-color: #F0A92A;
  color: #1C1C1E;
}

*:focus-visible {
  outline: 2px solid #F0A92A;
  outline-offset: 2px;
}

input:focus-visible,
select:focus-visible,
textarea:focus-visible,
.rounded-full:focus-visible {
  outline: none;
}

/* ─── Layout Utilities ───────────────────────────────────── */
.scrollbar-none {
  scrollbar-width: none;
  -ms-overflow-style: none;
}
.scrollbar-none::-webkit-scrollbar {
  display: none !important;
}

.section-padding {
  padding-top: var(--section-y);
  padding-bottom: var(--section-y);
}

.container-wide {
  max-width: 80rem;
  margin-left: auto;
  margin-right: auto;
  padding-left: 1rem;
  padding-right: 1rem;
}

@media (min-width: 640px) {
  .container-wide {
    padding-left: 1.5rem;
    padding-right: 1.5rem;
  }
}

@media (min-width: 1024px) {
  .container-wide {
    padding-left: 2rem;
    padding-right: 2rem;
  }
}

/* ─── Buttons ────────────────────────────────────────────── */
.btn-primary,
.btn-amber,
.btn-ghost,
.btn-ghost-white {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 0.5rem;
  padding: 0.75rem 1.5rem;
  border-radius: 999px;
  font-family: 'Inter', system-ui, sans-serif;
  font-weight: 500;
  font-size: 0.875rem;
  min-height: 44px;
  transition: all 0.2s ease;
  border: none;
  cursor: pointer;
  text-decoration: none;
  line-height: 1;
}

.btn-primary {
  background-color: #1A3A5C;
  color: white;
}

.btn-primary:hover {
  background-color: #243f68;
  box-shadow: 0 8px 32px 0 rgba(26, 58, 92, 0.16);
  transform: translateY(-2px);
}

.btn-primary:active {
  transform: translateY(0);
}

.btn-amber {
  background-color: #F0A92A;
  color: #1C1C1E;
}

.btn-amber:hover {
  background-color: #D48B0E;
  box-shadow: 0 8px 32px 0 rgba(26, 58, 92, 0.16);
  transform: translateY(-2px);
}

.btn-amber:active {
  transform: translateY(0);
}

.btn-ghost {
  border: 1px solid #1A3A5C;
  color: #1A3A5C;
  background: transparent;
}

.btn-ghost:hover {
  background-color: #1A3A5C;
  color: white;
  transform: translateY(-2px);
}

.btn-ghost-white {
  border: 1px solid white;
  color: white;
  background: transparent;
}

.btn-ghost-white:hover {
  background-color: white;
  color: #1A3A5C;
  transform: translateY(-2px);
}

/* ─── Card ───────────────────────────────────────────────── */
.card {
  background: white;
  border-radius: 32px;
  box-shadow: 0 2px 16px rgba(26, 58, 92, 0.06);
}

/* ─── Luxury Section Backgrounds ────────────────────────── */

/* Consolidated Cream mesh background with 2 static radial gradients */
.section-bg-soft {
  background-color: #FBF7F0;
  background-image:
    radial-gradient(at 10% 20%, rgba(240, 169, 42, 0.04) 0px, transparent 45%),
    radial-gradient(at 90% 80%, rgba(74, 127, 165, 0.05) 0px, transparent 45%);
}

/* Consolidated Dark mesh background with 1 static radial gradient */
.section-bg-dark {
  background-color: #111827;
  background-image:
    radial-gradient(at 80% 20%, rgba(74, 127, 165, 0.06) 0px, transparent 50%);
}

/* Consolidated Emerald mesh background with 1 static radial gradient */
.section-bg-emerald {
  background-color: #022c22;
  background-image:
    radial-gradient(at 50% 0%, rgba(16, 185, 129, 0.06) 0px, transparent 50%);
}

/* ─── Badges ─────────────────────────────────────────────── */
.badge {
  display: inline-block;
  padding: 0.25rem 0.75rem;
  border-radius: 999px;
  font-size: 0.75rem;
  font-weight: 500;
  font-family: 'Inter', system-ui, sans-serif;
}

.badge-blue {
  background: #EFF6FF;
  color: #1A3A5C;
}

.badge-amber {
  background: #FFFBEB;
  color: #D48B0E;
}

.badge-sand {
  background: #F0EAD8;
  color: #6E6A66;
}

/* ─── Typography Helpers ─────────────────────────────────── */
.section-label {
  font-size: 0.75rem;
  font-family: 'Inter', system-ui, sans-serif;
  font-weight: 600;
  letter-spacing: 0.1em;
  text-transform: uppercase;
  color: #4A7FA5;
}

.section-title {
  font-family: 'Playfair Display', Georgia, serif;
  font-size: clamp(1.75rem, 3vw, 3rem);
  color: #1C1C1E;
  line-height: 1.2;
}

.section-subtitle {
  font-family: 'Inter', system-ui, sans-serif;
  font-size: clamp(1rem, 1.5vw, 1.125rem);
  color: #6E6A66;
  line-height: 1.65;
  max-width: 42rem;
}

/* ─── Navbar Pill ────────────────────────────────────────── */
.nav-pill {
  position: fixed;
  top: 1rem;
  left: 50%;
  transform: translateX(-50%);
  z-index: 50;
  width: calc(100% - 2rem);
  max-width: 72rem;
  background-color: rgba(255, 255, 255, 0.85);
  backdrop-filter: blur(12px);
  border-radius: 999px;
  box-shadow: 0 4px 24px 0 rgba(26, 58, 92, 0.10);
  border: 1px solid rgba(255, 255, 255, 0.6);
  transition: all 0.3s ease;
}

/* ─── Hero Overlay ───────────────────────────────────────── */
.hero-overlay {
  background: linear-gradient(to bottom,
      rgba(26, 58, 92, 0.60) 0%,
      rgba(26, 58, 92, 0.30) 50%,
      rgba(0, 0, 0, 0.15) 100%);
  position: absolute;
  inset: 0;
}

/* ─── Scroll Reveal ──────────────────────────────────────── */
.reveal {
  opacity: 0;
  transform: translateY(1.5rem);
  transition: all 0.7s ease-out;
}

.reveal.visible {
  opacity: 1;
  transform: translateY(0);
}

/* ─── Scrollbar ──────────────────────────────────────────── */
::-webkit-scrollbar {
  width: 6px;
}

::-webkit-scrollbar-track {
  background: #FBF7F0;
}

::-webkit-scrollbar-thumb {
  background: #4A7FA5;
  border-radius: 999px;
}

::-webkit-scrollbar-thumb:hover {
  background: #1A3A5C;
}

/* ─── Map Pulse Animation ────────────────────────────────── */
@keyframes mapPulse {
  0% {
    transform: scale(0.8);
    opacity: 0.7;
  }
  70% {
    transform: scale(1.8);
    opacity: 0;
  }
  100% {
    transform: scale(0.8);
    opacity: 0;
  }
}

.animate-map-pulse {
  animation: mapPulse 2.4s cubic-bezier(0.4, 0, 0.2, 1) infinite;
}

@media (prefers-reduced-motion: reduce) {
  .animate-map-pulse {
    animation: none;
  }
}

@keyframes gradientMove {
  0%, 100% { background-position: 0% 50%; }
  50% { background-position: 100% 50%; }
}
.animate-gradient-slow {
  background-size: 200% 200%;
  animation: gradientMove 15s ease infinite;
}

@keyframes lineShimmer {
  0% { transform: translateX(-100%); }
  100% { transform: translateX(100%); }
}
.animate-line-shimmer {
  position: relative;
  overflow: hidden;
}
.animate-line-shimmer::after {
  content: '';
  position: absolute;
  top: 0;
  bottom: 0;
  left: 0;
  width: 50%;
  background: linear-gradient(90deg, transparent, rgba(232, 165, 61, 0.3), transparent);
  animation: lineShimmer 3.5s infinite ease-in-out;
}

